test('should set permission mode', () => {
  const agent = new TestAgent({
    role: 'test',
    systemPrompt: 'test',
    allowedTools: []
  });

  agent.setPermissionMode('bypassPermissions');
  expect(agent.getPermissionMode()).toBe('bypassPermissions');
